        </form>
      );
    };

    render(<App />);

    fireEvent.click(screen.getByRole('button', { name: 'Set same' }));

    expect(callbackFn).not.toHaveBeenCalled();
  });

  it('should call subscribe callback with a values snapshot', async () => {
    const callbackFn = jest.fn();
